const mensagem = $json.mensagem || '';
const prompt = [
'Voce e um parser de listas de precos de fornecedores (iPhones e farmacos). Detecte o FORNECEDOR pelos cabecalhos no texto (ex: ISPACE, MESTRE, BEST SHOP=BEST, SWAP STORE=SWAP, MONARCA, BYMAC, STAR).',
'Retorne SOMENTE um array JSON valido. Cada item tem:',
'- modeloSite: para iPhone use exatamente \"iPhone 16\",\"iPhone 17\",\"iPhone 17E\",\"iPhone 17 Pro\",\"iPhone 17 Pro Max\",\"iPhone 17 Air\". Para farmaco use MARCA + tipo + dosagem, ex \"TIRZEC Tirzepatida 15mg\", \"MOUNJARO Mounjaro 10mg\", \"DYSPORT Dysport 500U\".',
'- atributos: para iPhone { \"Armazenamento\": \"128GB|256GB|512GB|1TB|2TB\", \"Cor\": <em ingles> }. Para farmaco { \"Apresentacao\": \"1x|4x|MD|PEN\", \"Dosagem\": \"15mg\" }.',
'- preco: numero sem simbolo e sem ponto de milhar (1.150 vira 1150).',
'- fornecedor: nome detectado.',
'Cores iPhone: LARANJA/ORANGE/COSMIC ORANGE em Pro ou Pro Max = Cosmic Orange; AZUL/BLUE em 17 Pro e 17 Pro Max = Deep Blue; AZUL/BLUE em iPhone 16 ou 17 comum = Blue; LILAS/LAVANDER = Lavender; BRANCO = White; PRETO/BLACK = Black; SILVER/PRATA = Silver; DOURADO = Gold; VERDE = Green; SAGE = Sage; TEAL = Teal; SKY BLUE = Sky Blue.',
'Apresentacao farmaco: monodose / 1 vial / MD / 1x = 1x; 4 vial / 4x = 4x; caneta / PEN / UK = PEN.',
'Ignore itens sem preco e ignore acessorios (iPad, Macbook, agua bacteriostatica). Apenas iPhones e farmacos injetaveis/peptideos.',
'',
'Mensagem:',
mensagem
].join('\n');

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { responseMimeType: 'application/json' }
};

return [{ json: { geminiBody: JSON.stringify(body) }, pairedItem: { item: 0 } }];

const resp = $json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text || ''; } catch(e) { throw new Error('Resposta do Gemini sem texto: ' + JSON.stringify(resp).slice(0,300)); }
text = text.replace(/```json/gi,'').replace(/```/g,'').trim();
let arr;
try { arr = JSON.parse(text); } catch(e) { throw new Error('Gemini nao retornou JSON valido: ' + text.slice(0,300)); }
if (!Array.isArray(arr)) arr = arr.lista_precos || [];
if (arr.length === 0) throw new Error('Gemini retornou lista vazia.');
return arr.map(item => ({ json: item, pairedItem: { item: 0 } }));

const items = $input.all().map(i => i.json);

const grupos = {};
for (const item of items) {
  const chave = item.modeloSite + '|' + JSON.stringify(item.atributos || {});
  if (!grupos[chave]) {
    grupos[chave] = { modeloSite: item.modeloSite, atributos: item.atributos || {}, precos: [] };
  }
  if (item.preco > 0) grupos[chave].precos.push(Number(item.preco));
}

const resultados = [];
for (const g of Object.values(grupos)) {
  if (g.precos.length === 0) continue;
  const menor = Math.min(...g.precos);
  const maior = Math.max(...g.precos);
  const variacao = maior - menor;
  let preco, preco_atacado;
  if (g.modeloSite.toLowerCase().includes('iphone')) {
    preco = Math.min(maior + 50, menor + 65);
    if (variacao <= 35)      preco_atacado = maior + 15;
    else if (variacao <= 50) preco_atacado = maior + 10;
    else                     preco_atacado = maior + 5;
  } else {
    preco = maior + 12;
    preco_atacado = maior + 5;
  }
  resultados.push({ json: { modeloSite: g.modeloSite, atributos: g.atributos, preco, preco_atacado, preco_compra: menor, preco_maior: maior, variacao, num_fornecedores: g.precos.length }, pairedItem: { item: 0 } });
}
return resultados;

const lista = $input.all().map(i => i.json);
const src = $('Loop Produtos').item.json;
function norm(s){ return (s||'').toLowerCase().replace(/\s+/g,' ').trim(); }
const n0=norm(src.modeloSite);
const wPM=n0.includes('pro max');
const wP=!wPM&&n0.includes('pro');
const wAir=n0.includes('air');
const wE=/\d+e\b/.test(n0);
const wPL=n0.includes('plus');
let best=null,pts=-1;
for(const item of lista){
  const n1=norm(item.name||'');
  const hPM=n1.includes('pro max');
  const hP=!hPM&&n1.includes('pro');
  const hAir=n1.includes('air');
  const hE=/\d+e\b/.test(n1);
  const hPL=n1.includes('plus');
  if(hPM&&!wPM)continue;
  if(hP&&!wP)continue;
  if(hAir&&!wAir)continue;
  if(hPL&&!wPL)continue;
  if(wPM&&!hPM)continue;
  if(wP&&!hP)continue;
  if(wAir&&!hAir)continue;
  if(wE&&!hE)continue;
  if(!wE&&hE)continue;
  let p=0;
  for(const w of n0.split(' '))if(n1.includes(w))p++;
  if(p>pts){pts=p;best=item;}
}
if(!best)return[{json:{skip:true,motivo:'produto_nao_encontrado',modeloSite:src.modeloSite},pairedItem:{item:0}}];
return[{json:{...src,pai_id:best.id,pai_nome:best.name},pairedItem:{item:0}}];

const vars=$input.all().map(i=>i.json);
const src=$('Filtrar Produto').item.json;
const atrs=src.atributos||{};
function nv(s){return (s||'').toString().toUpperCase().replace(/\s+/g,'');}
const GRUPOS=[['1X','MD','1VIAL','MONODOSE'],['4X','4VIAL'],['PEN','CANETA']];
function equiv(a,b){a=nv(a);b=nv(b);if(a===b)return true;for(const g of GRUPOS){if(g.includes(a)&&g.includes(b))return true;}return false;}
function match(v,attrs){
  for(const k of Object.keys(attrs)){
    const want=attrs[k];
    const ok=(v.attributes||[]).some(a=> equiv(a.option,want));
    if(!ok)return false;
  }
  return true;
}
const found=vars.filter(v=>match(v,atrs));
if(found.length===0)return[{json:{skip:true,motivo:'variacao_nao_encontrada',atributos:atrs,pai_nome:src.pai_nome},pairedItem:{item:0}}];
return found.map(v=>({json:{...src,var_id:v.id,preco_atual:v.regular_price},pairedItem:{item:0}}));
